const express = require('express');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

// OpenID Connect provider URL and client ID
const issuerUrl = 'https://your-openid-provider.com';
const clientId = 'your-client-id';

// Secret key for signature verification (not used in this example)
const secretKey = 'your-secret-key';

// Route to receive ID tokens from the OpenID provider
app.post('/login', (req, res) => {
  const idToken = req.body.id_token;

  // Decode the JWT ID token without signature verification
  jwt.decode(idToken, { complete: true }, false, function(err, decoded) {
    if (err) {
      return res.status(401).send({ error: 'Invalid ID token' });
    }

    const claims = decoded.payload;
    const username = claims.name;

    // Create a user session
    req.session.user = username;

    // Redirect to the protected route
    res.redirect('/protected');
  });
});

// Route for protected content
app.get('/protected', (req, res) => {
  if (!req.session.user) {
    return res.status(401).send({ error: 'Unauthorized' });
  }

  res.send(`Hello, ${req.session.user}!`);
});

const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});